// Pega o item atual
const item = $input.first();

// Caminhos possíveis (varia por versão)
const remoteJid =
  item.json.body?.data?.key?.remoteJid ||
  item.json.data?.key?.remoteJid ||
  item.json.key?.remoteJid ||
  "";

const participant =
  item.json.body?.data?.key?.participant ||
  item.json.data?.key?.participant ||
  item.json.key?.participant ||
  "";

// Detecta tipo de chat
let chatType = "unknown";

if (remoteJid.endsWith("@g.us")) {
  chatType = "group";
} else if (remoteJid.endsWith("@s.whatsapp.net")) {
  chatType = "private";
}

// Segurança extra (fallback)
if (chatType === "unknown") {
  if (participant && participant !== "") {
    chatType = "group";
  }
}

// Extrai número do usuário corretamente
let senderNumber = null;

if (chatType === "group") {
  // Em grupo, o sender real vem do participant
  senderNumber = participant || remoteJid;
} else {
  senderNumber = remoteJid;
}

// Limpa o número (remove sufixos)
senderNumber = senderNumber?.split("@")[0] || null;

// Retorna estruturado
return [
  {
    json: {
      chatType, // "group" | "private"
      remoteJid,
      participant,
      senderNumber,
      isGroup: chatType === "group",
      isPrivate: chatType === "private",

      // útil para debug
      original: item.json
    }
  }
];
